#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <string.h>
#include <omp.h>

#ifdef TIMING
#include "timing.h"

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define DEVICE 0
#define HALO 1

void run(int argc, char **argv);

int rows, cols;
int *data;
int **wall;
int *result;
#define M_SEED 9
int pyramid_height;

void init(int argc, char **argv) {
    if (argc == 4) {
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
        pyramid_height = atoi(argv[3]);
    } else {
        printf("Usage: dynproc row_len col_len pyramid_height\n");
        exit(0);
    }

    data = new int[rows * cols];
    wall = new int *[rows];
    for (int n = 0; n < rows; n++) wall[n] = data + cols * n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            wall[i][j] = rand() % 10;
        }
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char *s) { fprintf(stderr, "error: %s\n", s); }

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) x = (x < (min)) ? (min) : ((x > (max)) ? (max) : (x))
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

static void dynproc_kernel(int iteration, int *gpuWall, int *gpuSrc, int *gpuResults, int cols,
                           int rows, int startStep, int border, int blockCols) {
#pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blockCols; bx++) {
        int prev[BLOCK_SIZE];
        int result_local[BLOCK_SIZE];
        unsigned char computed[BLOCK_SIZE];
        unsigned char computed_last[BLOCK_SIZE];

        int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;

        int blkX = small_block_cols * bx - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX + tx;
            if (IN_RANGE(xidx, 0, cols - 1)) {
                prev[tx] = gpuSrc[xidx];
            }
            computed_last[tx] = 0;
        }

        for (int i = 0; i < iteration; i++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int xidx = blkX + tx;

                int W = tx - 1;
                int E = tx + 1;

                W = (W < validXmin) ? validXmin : W;
                E = (E > validXmax) ? validXmax : E;

                bool isValid = IN_RANGE(tx, validXmin, validXmax);

                computed[tx] = 0;
                if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
                    computed[tx] = 1;
                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);
                    int index = cols * (startStep + i) + xidx;
                    result_local[tx] = shortest + gpuWall[index];
                }
            }

            if (i == iteration - 1) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) computed_last[tx] = computed[tx];
                break;
            }

            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                if (computed[tx]) prev[tx] = result_local[tx];
            }
        }

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            if (computed_last[tx]) {
                int xidx = blkX + tx;
                gpuResults[xidx] = result_local[tx];
            }
        }
    }
}

int calc_path(int *gpuWall, int *gpuResult[2], int rows, int cols, int pyramid_height, int blockCols,
              int borderCols) {
    int src = 1, dst = 0;
    for (int t = 0; t < rows - 1; t += pyramid_height) {
        int temp = src;
        src = dst;
        dst = temp;
        dynproc_kernel(MIN(pyramid_height, rows - t - 1), gpuWall, gpuResult[src], gpuResult[dst], cols, rows, t,
                       borderCols, blockCols);
    }
    return dst;
}

int main(int argc, char **argv) {
    run(argc, argv);
    return EXIT_SUCCESS;
}

void run(int argc, char **argv) {
    init(argc, argv);

    int borderCols = (pyramid_height)*HALO;
    int smallBlockCol = BLOCK_SIZE - (pyramid_height)*HALO * 2;
    int blockCols = cols / smallBlockCol + ((cols % smallBlockCol == 0) ? 0 : 1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",
           pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int *gpuWall, *gpuResult[2];
    int size = rows * cols;

    gpuResult[0] = new int[cols];
    gpuResult[1] = new int[cols];
    memcpy(gpuResult[0], data, sizeof(int) * cols);

    gpuWall = new int[size - cols];
    memcpy(gpuWall, data + cols, sizeof(int) * (size - cols));

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int final_ret = calc_path(gpuWall, gpuResult, rows, cols, pyramid_height, blockCols, borderCols);

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    memcpy(result, gpuResult[final_ret], sizeof(int) * cols);

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++) printf("%d ", data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++) printf("%d ", result[i]);
    printf("\n");
#endif

    delete[] gpuWall;
    delete[] gpuResult[0];
    delete[] gpuResult[1];

    delete[] data;
    delete[] wall;
    delete[] result;

#ifdef TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}
